import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { Carousel } from '../../includes';
import { insureUtilStrings } from '../utils';
import { Intro } from './Intro';
import { ServiceSummaryView } from '../Services';
import { KnowledgeArea } from "./KnowledeArea";
import { insureHomeStrings } from './config';
import { insureHomeActions } from './actions';

const style = theme => ({
    root: {
    },
    knowledge : {
    }
})
class _Home extends Component {
    componentDidMount() {
        const {
            dispatch,
            [insureHomeStrings.carousel] : carousel
        } = this.props;
        if(!carousel) insureHomeActions.getCarouel()(dispatch);
    }
    
    render() {
        const {classes,
            [insureUtilStrings.backendBaseUrl] : baseUrl,
            [insureHomeStrings.carousel] : carousel
        } = this.props;
        return (
            <div className={classes.root}>
                <Carousel
                    items={carousel ? carousel.values : []}
                    baseUrl={baseUrl}
                    />
                <Intro/>
                <ServiceSummaryView/>
                <KnowledgeArea classes={{root : classes.knowledge}}/>
            </div>
        );
    }
}


_Home.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({insureUtilReducer, insureHomeReducer}) => ({
    [insureUtilStrings.backendBaseUrl] : insureUtilReducer[insureUtilStrings.backendBaseUrl],
    [insureHomeStrings.carousel] : insureHomeReducer[insureHomeStrings.carousel],
})


export const Home = connect(mapStateToProps)(withStyles(style)(_Home));
export {Home as default}