import React, { Component } from 'react';
import { Typography } from '@material-ui/core';
import { connect } from "react-redux";
import {withStyles} from '@material-ui/core/styles'
import { insureUtil } from '../../utils';
import { insureHomeStrings } from '../config';
import { insureHomeActions } from '../actions';
import { insureServiceStrings } from '../../Services';

const style = theme => ({
    root : {
        display : "flex",
        flexDirection :"column",
        alignItems : "center",
        textAlign : "center",
        marginTop : 50,
        padding : 100,
        [theme.breakpoints.down("xs")] : {
            padding : 20
        },
        marginBottom : 100,
    },
    header : {
        width : "fit-content",
        color : insureUtil.getTheme().secondary,
        borderBottom : "solid 5px " + insureUtil.getTheme().primary,
        marginBottom : 50,
    },
    text : {
        fontSize : 21,
        fontStyle : "italic",
        [theme.breakpoints.down("xs")] : {
            fontSize : 18
        }
    }
})
class _Intro extends Component {
    componentDidMount() {
        const {dispatch} = this.props;
        insureHomeActions.getHomeInfo()(dispatch);
    }
    
    render() {
        const {classes, [insureHomeStrings.home] : homeInfo} = this.props;
        let introItem;
        if(homeInfo && homeInfo.values){
                const {item} = homeInfo.values.getFirstObjectByPropValue("name", "intro") || {};
                introItem = item;
        }
        return (
            <div className={classes.root}>
                <Typography variant="h4" className={classes.header} paragraph>
                    {introItem && introItem.header}
                </Typography>
                {introItem && introItem.value && introItem.value.map(
                    (item, index)=><Typography key={index} className={classes.text}>
                        {item}
                    </Typography>
                )}
            </div>
        )
    }
}
const mapStateToProps = ({insureHomeReducer, insureServiceReducer}) => ({
    [insureHomeStrings.home] : insureHomeReducer[insureHomeStrings.home],
    [insureServiceStrings.services] : insureServiceReducer[insureServiceStrings.services],
})
export const Intro = connect(mapStateToProps)(withStyles(style)(_Intro));
export {Intro as default};